import{_ as e,c as t,o as n,ag as s}from"./chunks/framework.ELrfyV9R.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"ai/2026-03/2026-03-14-cache.md","filePath":"ai/2026-03/2026-03-14-cache.md","lastUpdated":1776858534000}'),o={name:"ai/2026-03/2026-03-14-cache.md"};function r(i,a,c,l,p,d){return n(),t("div",null,a[0]||(a[0]=[s(`<p>Cache read 和 cache write 是 Anthropic <strong>Prompt Caching</strong> 功能的两个概念，用来节省 token 费用和提升响应速度。</p><h2 id="基本原理" tabindex="-1">基本原理 <a class="header-anchor" href="#基本原理" aria-label="Permalink to &quot;基本原理&quot;">​</a></h2><p>当你用 Claude Code 处理大型代码库时，每次请求都需要把上下文（代码文件、系统提示等）发送给 API。Prompt Caching 允许把这些内容&quot;缓存&quot;起来，避免重复处理。</p><h2 id="cache-write-缓存写入" tabindex="-1">Cache Write（缓存写入） <a class="header-anchor" href="#cache-write-缓存写入" aria-label="Permalink to &quot;Cache Write（缓存写入）&quot;">​</a></h2><ul><li>第一次把某段内容发送给 API 时，Anthropic 会将其存入缓存</li><li>这次请求会产生 <strong>cache write token</strong> 的费用</li><li>费用比普通 input token <strong>略贵一点</strong>（大约 1.25x），因为需要存储开销</li><li>缓存有效期通常是 <strong>5 分钟</strong>（TTL 会在每次命中时刷新）</li></ul><h2 id="cache-read-缓存读取" tabindex="-1">Cache Read（缓存读取） <a class="header-anchor" href="#cache-read-缓存读取" aria-label="Permalink to &quot;Cache Read（缓存读取）&quot;">​</a></h2><ul><li>后续请求中，如果包含相同的内容，API 直接从缓存读取，不重新处理</li><li>产生 <strong>cache read token</strong> 的费用</li><li>费用比普通 input token <strong>便宜很多</strong>（大约 0.1x，即九折优惠）</li><li>响应速度也更快</li></ul><h2 id="在-claude-code-中的实际意义" tabindex="-1">在 Claude Code 中的实际意义 <a class="header-anchor" href="#在-claude-code-中的实际意义" aria-label="Permalink to &quot;在 Claude Code 中的实际意义&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>第一次分析项目：</span></span>
<span class="line"><span>  → 读取大量代码文件 → Cache Write（稍贵）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>后续对话/修改：</span></span>
<span class="line"><span>  → 相同代码上下文直接复用 → Cache Read（很便宜）</span></span></code></pre></div><p>Claude Code 在处理大型代码库时会自动利用这个机制，所以你会看到账单或日志里区分这两种 token 类型。</p><h2 id="为什么要区分" tabindex="-1">为什么要区分？ <a class="header-anchor" href="#为什么要区分" aria-label="Permalink to &quot;为什么要区分？&quot;">​</a></h2><p>计费不同，所以 Anthropic 在用量统计里分开显示，让你清楚地看到实际节省了多少费用。如果一个会话里 cache read 占比很高，说明缓存命中率好，成本效率高。</p><p>![[Pasted image 20260314150013.png]]</p><p>对，理解完全正确。</p><p><strong>缓存是临时的</strong>，默认 TTL 是 <strong>5 分钟</strong>，每次命中会刷新计时。超时后缓存自动失效。</p><p><strong>新开会话后</strong>，缓存不会延续。第一次发送上下文又会产生 cache write，后续同一会话内的对话才会 cache read。</p><p>所以 Claude Code 的缓存收益主要体现在<strong>同一个长会话内</strong>的多轮对话，而不是跨会话复用。</p>`,17)]))}const g=e(o,[["render",r]]);export{u as __pageData,g as default};
